/* ---------------------------------------------------------------------------
 * 999 Blockchain-Themed Quest Definitions
 *
 * Template-based generation: each zone defines locations, enemies, and lore
 * templates. Quests are generated by combining these components.
 *
 * chain_quest_id = zone_id × 4 + difficulty_index
 *   Easy=0, Medium=1, Hard=2, Boss=3
 *
 * IDs start at 100 to avoid collision with legacy quests (0–31).
 * ------------------------------------------------------------------------- */

export interface QuestSeed {
  id: number;
  name: string;
  zone_id: number;
  difficulty: 'Easy' | 'Medium' | 'Hard' | 'Boss';
  duration_secs: number;
  win_xp: number;
  loss_xp: number;
  min_level: number;
  min_power_score: number;
  base_difficulty: number;
  description: string;
  lore_intro: string;
  lore_success: string;
  lore_failure: string;
  enemy_name: string;
  chain_quest_id: number;
}

export interface ZoneSeed {
  id: number;
  name: string;
  element: string;
  description: string;
  lore: string;
}

